import os
import logging

# Set up logging configuration
logging.basicConfig(filename='cleanup.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def clean_up_directory(directory):
    """
    Recursively deletes files from the specified directory.

    Args:
        directory (str): The path to the directory to clean up.
    """
    try:
        for item in os.listdir(directory):
            item_path = os.path.join(directory, item)
            if os.path.isfile(item_path):
                try:
                    os.remove(item_path)
                    logging.info(f"Deleted file: {item_path}")
                except Exception as e:
                    logging.error(f"Failed to delete file: {item_path}. Error: {e}")
            elif os.path.isdir(item_path):
                clean_up_directory(item_path)
    except Exception as e:
        logging.error(f"Error cleaning up directory: {directory}. Error: {e}")

def main():
    user_home_directory = os.path.expanduser('~') + '/home'
    clean_up_directory(user_home_directory)

if __name__ == "__main__":
    main()
```

**Explanation:**

1.  We set up a basic logging configuration using the `logging.basicConfig()` function, which logs messages to a file named `cleanup.log`. The log level is set to `INFO`, and the log format includes the timestamp, log level, and the log message.

