def get_age(file_time):
    """Calculate the age of a file in days."""
    return (datetime.datetime.now() - file_time).days

def cleanup_user_directory(user_directory):
    """Recursively clean up the user's home directory."""
    try:
        for root, dirs, files in os.walk(user_directory):
            for file in files:
                file_path = os.path.join(root, file)
                file_time = os.path.getctime(file_path)
                if get_age(file_time) > 30:
                    os.remove(file_path)
            for dir in dirs:
                dir_path = os.path.join(root, dir)
                if get_age(file_time) > 30:
                    os.rmdir(dir_path)
    except Exception as e:
        print(f"An error occurred: {e}")

def main():
